function solve(n, edges) {
    // DSU structure initialization
    const parent = Array(n).fill(0).map((_, i) => i);
    // distance[i] stores the parity of the path weight from node i to its current parent.
    const distance = Array(n).fill(0);

    // Find operation with path compression and distance update
    // Returns [root, parity_distance_to_root]
    const find = (i) => {
        if (parent[i] === i) {
            return [i, 0];
