        // Recursively find the root and the distance from parent[i] to the root
        const [root, root_dist] = find(parent[i]);

        // Path compression: set i's parent directly to the root
        parent[i] = root;

        // Update distance[i]: new distance = old distance (i -> parent[i]) XOR distance (parent[i] -> root)
        distance[i] = distance[i] ^ root_dist;

        return [root, distance[i]];
