            // Parity (root_u -> u) = dist_u
            // Parity (u -> v) = w
            // Parity (v -> root_v) = dist_v

            // Since the graph is undirected and we use XOR sums, parity(A->B) = parity(B->A).
            // Parity (root_u -> root_v) = dist_u ^ w ^ dist_v
            distance[root_u] = dist_u ^ w ^ dist_v;

